    #[test]
    fn session_entry_session_roundtrip() {
        let entry = SessionEntry::new_session(
            "abc-123".to_string(),
            "2025-01-01T00:00:00Z".to_string(),
            "/home/user".to_string(),
            "llama3.2".to_string(),
            32768,
        );
        let json = serde_json::to_string(&entry).unwrap();
        let decoded: SessionEntry = serde_json::from_str(&json).unwrap();
        assert_eq!(entry.id(), decoded.id());
    }

    #[test]
