    // ---------------------------------------------------------------------------
    // RequestTokenUsage
    // ---------------------------------------------------------------------------

    #[test]
    fn request_token_usage_total() {
        let usage = RequestTokenUsage { input_tokens: 100, output_tokens: 50, estimated: false };
        assert_eq!(usage.total(), 150);
    }

    #[test]
    fn request_token_usage_delta() {
        let prev = RequestTokenUsage { input_tokens: 100, output_tokens: 50, estimated: false };
        let curr = RequestTokenUsage { input_tokens: 200, output_tokens: 120, estimated: false };
        let delta = curr.delta(&prev);
        assert_eq!(delta.input_tokens, 100);
        assert_eq!(delta.output_tokens, 70);
    }

    #[test]
    fn request_token_usage_delta_saturates() {
        let prev = RequestTokenUsage { input_tokens: 200, output_tokens: 100, estimated: false };
        let curr = RequestTokenUsage { input_tokens: 100, output_tokens: 50, estimated: false };
        let delta = curr.delta(&prev);
        // Should saturate at 0, not underflow
        assert_eq!(delta.input_tokens, 0);
        assert_eq!(delta.output_tokens, 0);
    }

    #[test]
    fn request_token_usage_default() {
        let usage = RequestTokenUsage::default();
        assert_eq!(usage.input_tokens, 0);
        assert_eq!(usage.output_tokens, 0);
        assert_eq!(usage.total(), 0);
    }

