    #[test]
    fn session_entry_id_returns_correct_values() {
        let session = SessionEntry::new_session(
            "sess-1".to_string(), "ts".to_string(), "/".to_string(), "model".to_string(), 4096,
        );
        assert_eq!(session.id(), "sess-1");

        let msg = SessionEntry::new_message(Some("sess-1".to_string()), AgentMessage::user("hi".to_string()));
        assert!(!msg.id().is_empty());
        assert_eq!(msg.parent_id(), Some("sess-1".to_string()));
    }

